module top_module(
    Y ,
    A1,
    A2,
    B1
);output Y ;
    input  A1;
    input  A2;
    input  B1;

    // Voltage supply signals
    supply1 VPWR;
    supply0 VGND;
    supply1 VPB ;
    supply0 VNB ;

    wire neg_xor_result = (B1 == 1'b0);
    assign Y = neg_xor_result ? 1'b0 : (A1 ^ A2);

endmodule
